const input = $input.first().json;
const body = input.body || input;
const data = body.Data || {};
const extra = body.Extra || {};
const stats = data.BackendStatistics || {};

const jobName = extra['backup-name'] || extra.OperationName || 'Unknown Job';
const status = data.ParsedResult || 'Unknown';
const duration = data.Duration || '';
const filesExamined = data.ExaminedFiles || 0;
const filesAdded = data.AddedFiles || 0;
const filesModified = data.ModifiedFiles || 0;
const filesDeleted = data.DeletedFiles || 0;
const sizeExamined = data.SizeOfExaminedFiles || 0;
const bytesUploaded = stats.BytesUploaded || 0;
const bytesDownloaded = stats.BytesDownloaded || 0;
const errorsCount = data.ErrorsActualLength || 0;
const warningsCount = data.WarningsActualLength || 0;
const version = data.Version || '';
const endTime = data.EndTime || '';

const isSuccess = status === 'Success' && errorsCount === 0;
const isWarning = status === 'Warning' || (warningsCount > 0 && errorsCount === 0);
const isError = status === 'Error' || status === 'Fatal' || errorsCount > 0;

// Format bytes to human readable
function formatBytes(bytes) {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return (bytes / Math.pow(k, i)).toFixed(1) + ' ' + sizes[i];
}

let color, emoji;
if (isError) { color = 15158332; emoji = '\ud83d\udd34'; }
else if (isWarning) { color = 16776960; emoji = '\u26a0\ufe0f'; }
else { color = 3066993; emoji = '\u2705'; }

let description = `**Status:** ${status}`;
description += `\n**Duration:** ${duration}`;
description += `\n**Files examined:** ${filesExamined}`;
if (filesAdded > 0) description += `\n**Files added:** ${filesAdded}`;
if (filesModified > 0) description += `\n**Files modified:** ${filesModified}`;
if (filesDeleted > 0) description += `\n**Files deleted:** ${filesDeleted}`;
description += `\n**Size examined:** ${formatBytes(sizeExamined)}`;
if (bytesUploaded > 0) description += `\n**Uploaded:** ${formatBytes(bytesUploaded)}`;
if (errorsCount > 0) description += `\n\n**Errors:** ${errorsCount}`;
if (warningsCount > 0) description += `\n**Warnings:** ${warningsCount}`;

return [{
  json: {
    isSuccess,
    isError,
    isWarning,
    discordBody: {
      embeds: [{
        title: `${emoji} Backup ${status} — ${jobName}`,
        description: description.substring(0, 2000),
        color: color,
        timestamp: endTime || new Date().toISOString()
      }]
    }
  }
}];
